let mut error_groups: HashMap<ErrorKey, ErrorGroup> = HashMap::new();

for (file_idx, path) in files.iter().enumerate() {
    let file = File::open(path).unwrap_or_else(|e| {
        eprintln!("Error opening {}: {e}", path.display());
        std::process::exit(1);
    });

    let filename = path
        .file_name()
