                // Directory: expand file globs inside it (non-recursive).
                for fg in &file_globs {
                    let full = format!("{}/{fg}", path.display());
                    match glob::glob(&full) {
                        Ok(paths) => {
                            for entry in paths.flatten() {
                                if entry.is_file() {
                                    files.push(entry);
                                }
                            }
                        }
                        Err(e) => {
                            eprintln!("Bad glob {full:?}: {e}");
                            std::process::exit(1);
                        }
                    }
                }
            } else {
